#include <stdio.h>
#include <stdlib.h>

struct Queue {
    int *items;
    int front;
    int rear;
    int size;
    int capacity;
};

struct Queue* createQueue(int capacity) {
    struct Queue* queue = (struct Queue*)malloc(sizeof(struct Queue));
    queue->capacity = capacity;
    queue->front = 0;
    queue->size = 0;
    queue->rear = capacity - 1; // This is important for proper circular behavior
    queue->items = (int*)malloc(queue->capacity * sizeof(int));
    return queue;
}

int isFull(struct Queue* queue) {
    return (queue->size == queue->capacity);
}

int isEmpty(struct Queue* queue) {
    return (queue->size == 0);
}

void enqueue(struct Queue* queue, int item) {
    if (isFull(queue))
        return;
    queue->rear = (queue->rear + 1) % queue->capacity;
    queue->items[queue->rear] = item;
    queue->size = queue->size + 1;
}

int dequeue(struct Queue* queue) {
    if (isEmpty(queue))
        return -1;
    int item = queue->items[queue->front];
    queue->front = (queue->front + 1) % queue->capacity;
    queue->size = queue->size - 1;
    return item;
}

int main() {
    int t;
    scanf("%d", &t); // Number of test cases 

    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k); // Number of pearls, Number of positions to move

        struct Queue* necklace = createQueue(n); // Use Queue

        // Enqueue the elements (pearls) into the queue
        for (int i = 0; i < n; i++) {
            int pearl;
            scanf("%d", &pearl);
            enqueue(necklace, pearl);
        }

        // Rotate the queue left by k positions
        for (int i = 0; i < k; i++) {
            int removed = dequeue(necklace);
            enqueue(necklace, removed);
        }

        // Print the modified necklace
        while (!isEmpty(necklace)) {
            int pearl = dequeue(necklace);
            printf("%d ", pearl);
        }

        printf("\n"); // Move to the next line for the next test case

        free(necklace->items);
        free(necklace);
    }

    return 0;
}

